// ❌ BAD - using DELETE to clear a 10-million-row staging table before a nightly load
DELETE FROM StagingOrders;
-- Logs every single row deletion, fires any triggers, takes minutes

// ✅ GOOD - use TRUNCATE for fast full-table clear before a reload
TRUNCATE TABLE StagingOrders;
-- Deallocates pages, minimal log, resets identity, no triggers, takes seconds

-- Use DELETE only when you need a WHERE filter
DELETE FROM Orders WHERE OrderDate < '2020-01-01';

-- Use DROP only when the table is no longer needed at all
DROP TABLE IF EXISTS StagingOrders;

// ❌ BAD - using INNER JOIN when the requirement is 'all customers even without orders'
SELECT c.Name, o.Total
FROM Customers c
INNER JOIN Orders o ON c.CustomerId = o.CustomerId;
-- Customers with no orders disappear silently from the results

// ✅ GOOD - LEFT JOIN keeps all customers, NULLs for customers with no orders
SELECT c.Name, ISNULL(o.Total, 0) AS TotalSpent
FROM Customers c
LEFT JOIN Orders o ON c.CustomerId = o.CustomerId;

-- Anti-join: customers who have NEVER placed an order
SELECT c.Name
FROM Customers c
LEFT JOIN Orders o ON c.CustomerId = o.CustomerId
WHERE o.CustomerId IS NULL;

-- FULL OUTER: all customers and all orphan orders
SELECT c.Name, o.OrderId
FROM Customers c
FULL OUTER JOIN Orders o ON c.CustomerId = o.CustomerId;

// ❌ BAD - non-SARGable predicate, full table scan even with an index on OrderDate
SELECT OrderId, CustomerId, Total
FROM Orders
WHERE YEAR(OrderDate) = 2024;

// ✅ GOOD - SARGable date range, allows index seek on OrderDate
SELECT OrderId, CustomerId, Total
FROM Orders
WHERE OrderDate >= '2024-01-01' AND OrderDate < '2025-01-01';

-- Measure I/O before and after any change
SET STATISTICS IO ON;
SET STATISTICS TIME ON;

-- Covering index to eliminate Key Lookup for a common customer order query
CREATE NONCLUSTERED INDEX IX_Orders_CustomerId_Cover
    ON Orders (CustomerId)
    INCLUDE (OrderDate, Total);

// ❌ BAD - table variable for 100k rows, optimizer guesses 1 row, picks wrong join type
DECLARE @RecentOrders TABLE (OrderId INT, CustomerId INT, Total DECIMAL(18,2));
INSERT INTO @RecentOrders
    SELECT OrderId, CustomerId, Total FROM Orders
    WHERE OrderDate > DATEADD(MONTH, -3, GETDATE());
-- Optimizer assumes @RecentOrders has 1 row -> nested loop on 100k rows -> slow

// ✅ GOOD - temp table for large intermediate sets, real statistics, accurate plans
CREATE TABLE #RecentOrders (OrderId INT, CustomerId INT, Total DECIMAL(18,2));
INSERT INTO #RecentOrders
    SELECT OrderId, CustomerId, Total FROM Orders
    WHERE OrderDate > DATEADD(MONTH, -3, GETDATE());
CREATE INDEX IX_RecentOrders_Customer ON #RecentOrders (CustomerId);
SELECT * FROM #RecentOrders;
DROP TABLE IF EXISTS #RecentOrders;

// ❌ BAD - scalar logic assumes INSERTED has exactly one row, breaks on bulk insert
CREATE TRIGGER trg_Orders_BadInsert ON Orders AFTER INSERT
AS BEGIN
    DECLARE @OrderId INT = (SELECT OrderId FROM INSERTED);
    INSERT INTO OrderAudit VALUES (@OrderId, GETUTCDATE());
END;
-- Fails or returns wrong data if more than one row is inserted

// ✅ GOOD - set-based logic handles any number of rows
CREATE OR ALTER TRIGGER trg_Orders_AfterInsert
ON Orders
AFTER INSERT
AS
BEGIN
    SET NOCOUNT ON;
    INSERT INTO OrderAudit (OrderId, CustomerId, Total, AuditAction, AuditDate)
    SELECT i.OrderId, i.CustomerId, i.Total, 'INSERT', GETUTCDATE()
    FROM INSERTED i;
END;

// ❌ BAD - non-clustered index on CustomerId but query selects OrderDate and Total
-- Execution plan shows: Index Seek -> Key Lookup (once per matching row)
CREATE NONCLUSTERED INDEX IX_Orders_CustomerId
    ON Orders (CustomerId);
SELECT OrderId, OrderDate, Total FROM Orders WHERE CustomerId = 42;

// ✅ GOOD - covering index eliminates Key Lookup
CREATE NONCLUSTERED INDEX IX_Orders_CustomerId_Cover
    ON Orders (CustomerId)
    INCLUDE (OrderDate, Total);
SELECT OrderId, OrderDate, Total FROM Orders WHERE CustomerId = 42;

// ❌ BAD - filtering on a window function directly in WHERE, causes error
SELECT EmployeeId, Name, Salary,
       DENSE_RANK() OVER (PARTITION BY Department ORDER BY Salary DESC) AS Rnk
FROM Employees
WHERE Rnk = 1;
-- Error: Rnk does not exist yet at WHERE processing time

// ✅ GOOD - wrap in CTE to filter on the window function result
WITH RankedEmployees AS (
    SELECT
        EmployeeId, Name, Department, Salary,
        ROW_NUMBER()  OVER (PARTITION BY Department ORDER BY Salary DESC) AS RowNum,
        RANK()        OVER (PARTITION BY Department ORDER BY Salary DESC) AS Rnk,
        DENSE_RANK()  OVER (PARTITION BY Department ORDER BY Salary DESC) AS DenseRnk
    FROM Employees
)
SELECT * FROM RankedEmployees WHERE DenseRnk = 1;

// ❌ BAD - index on CustomerId only, query needs OrderDate and Total
-- Execution plan: Index Seek -> Key Lookup per matched row
CREATE NONCLUSTERED INDEX IX_Orders_CustomerId
    ON Orders (CustomerId);
SELECT OrderId, OrderDate, Total FROM Orders WHERE CustomerId = 42;

// ✅ GOOD - covering index, OrderDate and Total in INCLUDE, no Key Lookup
CREATE NONCLUSTERED INDEX IX_Orders_CustomerId_Cover
    ON Orders (CustomerId)
    INCLUDE (OrderDate, Total);
SELECT OrderId, OrderDate, Total FROM Orders WHERE CustomerId = 42;

-- Find missing index suggestions from the plan cache
SELECT mid.statement, mid.equality_columns, mid.include_columns,
       migs.avg_user_impact
FROM sys.dm_db_missing_index_details mid
JOIN sys.dm_db_missing_index_groups mig ON mid.index_handle = mig.index_handle
JOIN sys.dm_db_missing_index_group_stats migs ON mig.index_group_handle = migs.group_handle
ORDER BY migs.avg_user_impact DESC;

// ❌ BAD - non-SARGable: YEAR() wraps the column, forces full table scan
SELECT * FROM Orders WHERE YEAR(OrderDate) = 2024;

// ✅ GOOD - SARGable: range comparison on the column, allows index seek
SELECT OrderId, CustomerId, Total
FROM Orders
WHERE OrderDate >= '2024-01-01' AND OrderDate < '2025-01-01';

-- Implicit type conversion when column is VARCHAR but parameter is NVARCHAR
DECLARE @Email NVARCHAR(200) = N'alice@company.com';
SELECT * FROM Customers WHERE Email = @Email;
-- If Email column is VARCHAR, SQL Server converts every row -> scan
-- Fix: match the parameter type to the column type

-- Check and update statistics
DBCC SHOW_STATISTICS ('Orders', 'IX_Orders_OrderDate');
UPDATE STATISTICS Orders WITH FULLSCAN;

// ❌ BAD - using UNION when sets are already disjoint, paying for unnecessary deduplication
SELECT OrderId, Total, 'Online' AS Channel FROM OnlineOrders
UNION
SELECT OrderId, Total, 'Store'  AS Channel FROM StoreOrders;
-- Sorts or hashes millions of rows to find duplicates that cannot exist

// ✅ GOOD - UNION ALL when sets are disjoint, no deduplication overhead
SELECT OrderId, Total, 'Online' AS Channel FROM OnlineOrders
UNION ALL
SELECT OrderId, Total, 'Store'  AS Channel FROM StoreOrders
ORDER BY Total DESC;

-- UNION is correct when deduplication is genuinely needed
SELECT CustomerId FROM ActiveCustomers
UNION
SELECT CustomerId FROM ArchivedCustomers;
-- A customer may exist in both tables - UNION removes that duplicate

// ❌ BAD - string concatenation: SQL injection risk and no plan reuse
DECLARE @sql NVARCHAR(500);
SET @sql = 'SELECT * FROM Orders WHERE CustomerId = ' + CAST(@CustomerId AS VARCHAR);
EXEC(@sql);
-- Risk: attacker controls @CustomerId and can inject SQL

// ✅ GOOD - stored procedure with parameters: safe, cached, permissioned
CREATE OR ALTER PROCEDURE usp_GetCustomerOrders
    @CustomerId INT,
    @StartDate  DATE = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT o.OrderId, o.Total, o.OrderDate
    FROM Orders o
    WHERE o.CustomerId = @CustomerId
      AND (@StartDate IS NULL OR o.OrderDate >= @StartDate)
    ORDER BY o.OrderDate DESC;
END;

-- Parameterized inline SQL is equally safe and cached
EXEC sp_executesql
    N'SELECT OrderId, Total FROM Orders WHERE CustomerId = @cid AND OrderDate >= @dt',
    N'@cid INT, @dt DATE',
    @cid = 42, @dt = '2024-01-01';
